  "properties": {
    "metric_name": {
      "type": "string"
    },
    "from_minutes_ago": {
      "default": 60,
      "type": "integer"
    },
    "to_minutes_ago": {
      "default": 0,
      "type": "integer"
    },
    "cluster": {
      "anyOf": [
        {
          "type": "string"
